+    // Check if this looks like a labeled block expression wrapped in parens
+    // Pattern: (__mN_xxx: { ... })  or  (__mN_xxx: { ... }))
+    const is_wrapped_labeled_block = has_labeled_block_pattern and
+        std.mem.indexOf(u8, expr_output, "((__m") != null;
